exports.control = {input : function(type,name) {
	var control = "<input type=\""+type+"\" name=\""+name+"\" id=\""+ name+"\" placeholder=\""+name+"\">";
	return control;
},
label : function(name) {
	var label = "<label title=\""+name+"\">"+name+"</label>";
	return label;
},
form : function(url) {
	var form = "<form method=\"post\" action=\""+url+"\" id=\""+form+"\" > hi </form>";
	return form;
},
form : function(url,controls) {
	var form = "<form method=\"post\" action=\""+url+"\" id=\"form\" >"+controls+"</form>";
	return form;
}}

